sql:
SELECT 
    (SELECT COUNT(user_id) FROM users WHERE user_status = 'active') AS active_users,
    (SELECT SUM(num_instances) FROM datasets) AS total_instances;

SELECT 
    (SELECT COUNT(*) FROM models) AS total_models, 
    (SELECT SUM(dataset_size_bytes) FROM datasets) AS total_dataset_size;

SELECT DISTINCT model_name, model_type
FROM models
WHERE model_status = 'active';
